   159→type LeveledCompactorOptions struct {
   160→	// PE specifies the postings encoder. It is called when compactor is writing out the postings for a label name/value pair during compaction.
   161→	// If it is nil then the default encoder is used. At the moment that is the "raw" encoder. See index.EncodePostingsRaw for more.
   162→	PE index.PostingsEncoder
   163→
   164→	// PD specifies the postings decoder factory to return different postings decoder based on BlockMeta. It is called when opening a block or opening the index file.
   165→	// If it is nil then a default decoder is used, compatible with Prometheus v2.
   166→	PD PostingsDecoderFactory
   167→
   168→	// MaxBlockChunkSegmentSize is the max block chunk segment size. If it is 0 then the default chunks.DefaultChunkSegmentSize is used.
   169→	MaxBlockChunkSegmentSize int64
   170→
   171→	// MergeFunc is used for merging series together in vertical compaction. By default storage.NewCompactingChunkSeriesMerger(storage.ChainedSeriesMerge) is used.
   172→	MergeFunc storage.VerticalChunkSeriesMergeFunc
   173→
   174→	// BlockExcludeFilter is used to decide which blocks are exluded from compactions.
   175→	BlockExcludeFilter BlockExcludeFilterFunc
   176→
   177→	// EnableOverlappingCompaction enables compaction of overlapping blocks. In Prometheus it is always enabled.
   178→	// It is useful for downstream projects like Mimir, Cortex, Thanos where they have a separate component that does compaction.
   179→	EnableOverlappingCompaction bool
   180→
   181→	// Metrics is set of metrics for Compactor. By default, NewCompactorMetrics would be called to initialize metrics unless it is provided.
   182→	Metrics *CompactorMetrics
   183→	// UseUncachedIO allows bypassing the page cache when appropriate.
   184→	UseUncachedIO bool
   185→}
