   187→type PostingsDecoderFactory func(meta *BlockMeta) index.PostingsDecoder
   188→
   189→type BlockExcludeFilterFunc func(meta *BlockMeta) bool
   190→
   191→func DefaultPostingsDecoderFactory(_ *BlockMeta) index.PostingsDecoder {
   192→	return index.DecodePostingsRaw
   193→}
