   638→// instrumentedChunkWriter is used for level 1 compactions to record statistics
   639→// about compacted chunks.
   640→type instrumentedChunkWriter struct {
   641→	ChunkWriter
   642→
   643→	size    prometheus.Histogram
   644→	samples prometheus.Histogram
   645→	trange  prometheus.Histogram
   646→}
   647→
   648→func (w *instrumentedChunkWriter) WriteChunks(chunks ...chunks.Meta) error {
   649→	for _, c := range chunks {
   650→		w.size.Observe(float64(len(c.Chunk.Bytes())))
   651→		w.samples.Observe(float64(c.Chunk.NumSamples()))
   652→		w.trange.Observe(float64(c.MaxTime - c.MinTime))
   653→	}
   654→	return w.ChunkWriter.WriteChunks(chunks...)
   655→}
   656→
   657→// write creates a new block that is the union of the provided blocks into dir.
   658→func (c *LeveledCompactor) write(dest string, meta *BlockMeta, blockPopulator BlockPopulator, blocks ...BlockReader) (err error) {
   659→	dir := filepath.Join(dest, meta.ULID.String())
   660→	tmp := dir + tmpForCreationBlockDirSuffix
   661→	var closers []io.Closer
   662→	defer func(t time.Time) {
   663→		err = errors.Join(err, closeAll(closers))
   664→
   665→		// RemoveAll returns no error when tmp doesn't exist so it is safe to always run it.
   666→		if err := os.RemoveAll(tmp); err != nil {
   667→			c.logger.Error("removed tmp folder after failed compaction", "err", err.Error())
   668→		}
   669→		c.metrics.Ran.Inc()
   670→		c.metrics.Duration.Observe(time.Since(t).Seconds())
   671→	}(time.Now())
   672→
   673→	if err = os.RemoveAll(tmp); err != nil {
   674→		return err
   675→	}
   676→
   677→	if err = os.MkdirAll(tmp, 0o777); err != nil {
   678→		return err
   679→	}
   680→
   681→	// Populate chunk and index files into temporary directory with
   682→	// data of all blocks.
   683→	var chunkw ChunkWriter
   684→
   685→	chunkw, err = chunks.NewWriter(chunkDir(tmp), chunks.WithSegmentSize(c.maxBlockChunkSegmentSize), chunks.WithUncachedIO(c.useUncachedIO))
   686→	if err != nil {
   687→		return fmt.Errorf("open chunk writer: %w", err)
   688→	}
   689→	closers = append(closers, chunkw)
   690→	// Record written chunk sizes on level 1 compactions.
   691→	if meta.Compaction.Level == 1 {
   692→		chunkw = &instrumentedChunkWriter{
   693→			ChunkWriter: chunkw,
   694→			size:        c.metrics.ChunkSize,
   695→			samples:     c.metrics.ChunkSamples,
   696→			trange:      c.metrics.ChunkRange,
   697→		}
   698→	}
   699→
   700→	indexw, err := index.NewWriterWithEncoder(c.ctx, filepath.Join(tmp, indexFilename), c.postingsEncoder)
   701→	if err != nil {
   702→		return fmt.Errorf("open index writer: %w", err)
   703→	}
   704→	closers = append(closers, indexw)
   705→
   706→	if err := blockPopulator.PopulateBlock(c.ctx, c.metrics, c.logger, c.chunkPool, c.mergeFunc, blocks, meta, indexw, chunkw, AllSortedPostings); err != nil {
   707→		return fmt.Errorf("populate block: %w", err)
   708→	}
   709→
   710→	select {
   711→	case <-c.ctx.Done():
   712→		return c.ctx.Err()
   713→	default:
   714→	}
   715→
   716→	// We are explicitly closing them here to check for error even
   717→	// though these are covered under defer. This is because in Windows,
   718→	// you cannot delete these unless they are closed and the defer is to
   719→	// make sure they are closed if the function exits due to an error above.
   720→	var errs []error
   721→	for _, w := range closers {
   722→		errs = append(errs, w.Close())
   723→	}
   724→	closers = closers[:0] // Avoid closing the writers twice in the defer.
   725→	if err := errors.Join(errs...); err != nil {
   726→		return err
   727→	}
   728→
   729→	// Populated block is empty, so exit early.
   730→	if meta.Stats.NumSamples == 0 {
   731→		return nil
   732→	}
   733→
   734→	if _, err = writeMetaFile(c.logger, tmp, meta); err != nil {
   735→		return fmt.Errorf("write merged meta: %w", err)
   736→	}
   737→
   738→	// Create an empty tombstones file.
   739→	if _, err := tombstones.WriteFile(c.logger, tmp, tombstones.NewMemTombstones()); err != nil {
   740→		return fmt.Errorf("write new tombstones file: %w", err)
   741→	}
   742→
   743→	df, err := fileutil.OpenDir(tmp)
   744→	if err != nil {
   745→		return fmt.Errorf("open temporary block dir: %w", err)
   746→	}
   747→	defer func() {
   748→		if df != nil {
   749→			df.Close()
   750→		}
   751→	}()
   752→
   753→	if err := df.Sync(); err != nil {
   754→		return fmt.Errorf("sync temporary dir file: %w", err)
   755→	}
   756→
   757→	// Close temp dir before rename block dir (for windows platform).
   758→	if err = df.Close(); err != nil {
   759→		return fmt.Errorf("close temporary dir: %w", err)
   760→	}
   761→	df = nil
   762→
   763→	// Block successfully written, make it visible in destination dir by moving it from tmp one.
   764→	if err := fileutil.Replace(tmp, dir); err != nil {
   765→		return fmt.Errorf("rename block dir: %w", err)
   766→	}
   767→
   768→	return nil
   769→}
   770→
   771→type BlockPopulator interface {
   772→	PopulateBlock(ctx context.Context, metrics *CompactorMetrics, logger *slog.Logger, chunkPool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc, blocks []BlockReader, meta *BlockMeta, indexw IndexWriter, chunkw ChunkWriter, postingsFunc IndexReaderPostingsFunc) error
   773→}
   774→
   775→// IndexReaderPostingsFunc is a function to get a sorted posting iterator from a given index reader.
   776→type IndexReaderPostingsFunc func(ctx context.Context, reader IndexReader) index.Postings
   777→
   778→// AllSortedPostings returns a sorted all posting iterator from the input index reader.
   779→func AllSortedPostings(ctx context.Context, reader IndexReader) index.Postings {
   780→	k, v := index.AllPostingsKey()
   781→	all, err := reader.Postings(ctx, k, v)
   782→	if err != nil {
   783→		return index.ErrPostings(err)
   784→	}
   785→	return reader.SortedPostings(all)
   786→}
   787→
   788→type DefaultBlockPopulator struct{}
   789→
   790→// PopulateBlock fills the index and chunk writers with new data gathered as the union
   791→// of the provided blocks. It returns meta information for the new block.
   792→// It expects sorted blocks input by mint.
   793→func (DefaultBlockPopulator) PopulateBlock(ctx context.Context, metrics *CompactorMetrics, logger *slog.Logger, chunkPool chunkenc.Pool, mergeFunc storage.VerticalChunkSeriesMergeFunc, blocks []BlockReader, meta *BlockMeta, indexw IndexWriter, chunkw ChunkWriter, postingsFunc IndexReaderPostingsFunc) (err error) {
   794→	if len(blocks) == 0 {
   795→		return errors.New("cannot populate block from no readers")
   796→	}
   797→
   798→	var (
   799→		sets        []storage.ChunkSeriesSet
   800→		symbols     index.StringIter
   801→		closers     []io.Closer
   802→		overlapping bool
   803→	)
   804→	defer func() {
   805→		if cerr := closeAll(closers); cerr != nil {
   806→			err = errors.Join(err, fmt.Errorf("close: %w", cerr))
   807→		}
   808→		metrics.PopulatingBlocks.Set(0)
   809→	}()
   810→	metrics.PopulatingBlocks.Set(1)
   811→
   812→	globalMaxt := blocks[0].Meta().MaxTime
   813→	for i, b := range blocks {
   814→		select {
   815→		case <-ctx.Done():
   816→			return ctx.Err()
   817→		default:
   818→		}
   819→
   820→		if !overlapping {
   821→			if i > 0 && b.Meta().MinTime < globalMaxt {
   822→				metrics.OverlappingBlocks.Inc()
   823→				overlapping = true
   824→				logger.Info("Found overlapping blocks during compaction", "ulid", meta.ULID)
   825→			}
   826→			if b.Meta().MaxTime > globalMaxt {
   827→				globalMaxt = b.Meta().MaxTime
   828→			}
   829→		}
   830→
   831→		indexr, err := b.Index()
   832→		if err != nil {
   833→			return fmt.Errorf("open index reader for block %+v: %w", b.Meta(), err)
   834→		}
   835→		closers = append(closers, indexr)
   836→
   837→		chunkr, err := b.Chunks()
   838→		if err != nil {
   839→			return fmt.Errorf("open chunk reader for block %+v: %w", b.Meta(), err)
   840→		}
   841→		closers = append(closers, chunkr)
   842→
   843→		tombsr, err := b.Tombstones()
   844→		if err != nil {
   845→			return fmt.Errorf("open tombstone reader for block %+v: %w", b.Meta(), err)
   846→		}
   847→		closers = append(closers, tombsr)
   848→
   849→		postings := postingsFunc(ctx, indexr)
   850→		// Blocks meta is half open: [min, max), so subtract 1 to ensure we don't hold samples with exact meta.MaxTime timestamp.
   851→		sets = append(sets, NewBlockChunkSeriesSet(b.Meta().ULID, indexr, chunkr, tombsr, postings, meta.MinTime, meta.MaxTime-1, false))
   852→		syms := indexr.Symbols()
   853→		if i == 0 {
   854→			symbols = syms
   855→			continue
   856→		}
   857→		symbols = NewMergedStringIter(symbols, syms)
   858→	}
   859→
   860→	for symbols.Next() {
   861→		if err := indexw.AddSymbol(symbols.At()); err != nil {
   862→			return fmt.Errorf("add symbol: %w", err)
   863→		}
   864→	}
   865→	if err := symbols.Err(); err != nil {
   866→		return fmt.Errorf("next symbol: %w", err)
   867→	}
   868→
   869→	var (
   870→		ref      = storage.SeriesRef(0)
   871→		chks     []chunks.Meta
   872→		chksIter chunks.Iterator
   873→	)
   874→
   875→	set := sets[0]
   876→	if len(sets) > 1 {
   877→		// Merge series using specified chunk series merger.
   878→		// The default one is the compacting series merger.
   879→		set = storage.NewMergeChunkSeriesSet(sets, 0, mergeFunc)
   880→	}
   881→
   882→	// Iterate over all sorted chunk series.
   883→	for set.Next() {
   884→		select {
   885→		case <-ctx.Done():
   886→			return ctx.Err()
   887→		default:
   888→		}
   889→		s := set.At()
   890→		chksIter = s.Iterator(chksIter)
   891→		chks = chks[:0]
   892→		for chksIter.Next() {
   893→			// We are not iterating in a streaming way over chunks as
   894→			// it's more efficient to do bulk write for index and
   895→			// chunk file purposes.
   896→			chks = append(chks, chksIter.At())
   897→		}
   898→		if err := chksIter.Err(); err != nil {
   899→			return fmt.Errorf("chunk iter: %w", err)
   900→		}
   901→
   902→		// Skip series with all deleted chunks.
   903→		if len(chks) == 0 {
   904→			continue
   905→		}
   906→
   907→		if err := chunkw.WriteChunks(chks...); err != nil {
   908→			return fmt.Errorf("write chunks: %w", err)
   909→		}
   910→		if err := indexw.AddSeries(ref, s.Labels(), chks...); err != nil {
   911→			return fmt.Errorf("add series: %w", err)
   912→		}
   913→
   914→		meta.Stats.NumChunks += uint64(len(chks))
   915→		meta.Stats.NumSeries++
   916→		for _, chk := range chks {
   917→			samples := uint64(chk.Chunk.NumSamples())
   918→			meta.Stats.NumSamples += samples
   919→			switch chk.Chunk.Encoding() {
   920→			case chunkenc.EncHistogram, chunkenc.EncFloatHistogram:
   921→				meta.Stats.NumHistogramSamples += samples
   922→			case chunkenc.EncXOR:
   923→				meta.Stats.NumFloatSamples += samples
   924→			}
   925→		}
   926→
   927→		for _, chk := range chks {
   928→			if err := chunkPool.Put(chk.Chunk); err != nil {
   929→				return fmt.Errorf("put chunk: %w", err)
   930→			}
   931→		}
   932→		ref++
   933→	}
   934→	if err := set.Err(); err != nil {
   935→		return fmt.Errorf("iterate compaction set: %w", err)
   936→	}
   937→
   938→	return nil
   939→}
